from typing import List, Optional, Dictfrom pydantic import BaseModel, Fieldclass LineItem(BaseModel):    sku: Optional[str] = Field(default=None, description="SKU or product code")    description: Optional[str] = Field(default=None, description="Item description")    quantity: Optional[float] = Field(default=None, description="Quantity purchased")    unit_price: Optional[float] = Field(default=None, description="Unit price")    line_total: Optional[float] = Field(default=None, description="Total price for the line item")class ShipToLocation(BaseModel):    site_name: Optional[str] = Field(default=None, description="Name of the delivery site")    address: Optional[str] = Field(default=None, description="Full delivery address")    receiving_hours: Optional[str] = Field(default=None, description="Receiving hours if specified")    delivery_window: Optional[str] = Field(default=None, description="Preferred delivery window if specified")class InvoiceData(BaseModel):    vendor_name: Optional[str] = None    invoice_number: Optional[str] = None    invoice_date: Optional[str] = None    due_date: Optional[str] = None    payment_terms: Optional[str] = None    currency: Optional[str] = None    customer_po_number: Optional[str] = None    subtotal: Optional[float] = None    taxes: Optional[Dict[str, float]] = None    total_due: Optional[float] = None    ship_to_locations: List[ShipToLocation] = Field(default_factory=list)    notes: Optional[str] = None    line_items: List[LineItem] = Field(default_factory=list)